import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.server.Directives._
import akka.http.scaladsl.model._
import akka.stream.Materializer
import scala.xml.XML
import akka.event.Logging
import scala.concurrent.ExecutionContextExecutor

object ConfigService extends App {
  implicit val system: ActorSystem = ActorSystem("config-service")
  implicit val ec: ExecutionContextExecutor = system.dispatcher
  val logger = Logging(system, getClass)

  val route =
    post {
      path("parse") {
        entity(as[String]) { xmlString =>
          try {
            val xml = XML.loadString(xmlString)
            // Assuming the XML has the following structure:
            // <configuration>
            //   <setting name="setting1" value="value1" />
            //   <setting name="setting2" value="value2" />
            //   ...
            // </configuration>
            val settings = (xml \\ "setting").map { node =>
              val name = (node \ "@name").text
              val value = (node \ "@value").text
              name -> value
            }.toMap
            complete(HttpResponse(entity = s"Parsed settings: $settings"))
          } catch {
            case e: Exception =>
              logger.error("Error parsing XML: " + e.getMessage)
              complete(HttpResponse(StatusCodes.BadRequest, entity = s"Error parsing XML: ${e.getMessage}"))
          }
        }
      }
    }

  Http().newServerAt("localhost", 8080).bind(route)
  logger.info("Server online at http://localhost:8080/")
}